@Directive({ selector: '[appHighlight]', standalone: true })
export class HighlightDirective {
  @HostBinding('style.background') bg = '';
  @HostListener('mouseenter') on() { this.bg = 'yellow'; }
  @HostListener('mouseleave') off() { this.bg = ''; }
}

@Directive({ selector: '[appIf]', standalone: true })
export class IfDirective {
  constructor(private tpl: TemplateRef<any>, private vcr: ViewContainerRef) {}
  @Input() set appIf(cond: boolean) {
    this.vcr.clear();
    if (cond) this.vcr.createEmbeddedView(this.tpl);
  }
}

